root.render(
  <React.StrictMode>
    <GoogleOAuthProvider clientId="947397347573-0nephq36dtkfm710h9qrkn258lsqomul.apps.googleusercontent.com">
    <App />
    </GoogleOAuthProvider>
  </React.StrictMode>
);
